async function buildTrainingSet(symbols = TRAINING_UNIVERSE, log = console.log) {
  const rows = [];
  for (const symbol of symbols) {
    const bars = (await db.select().from(historicalPricesTable).where(eq(historicalPricesTable.symbol, symbol))).sort((a, b) => a.date.localeCompare(b.date)).map((r) => ({ date: r.date, open: r.open, high: r.high, low: r.low, close: r.close, volume: r.volume }));
    if (bars.length < 250) {
      log(`[pipeline] ${symbol}: insufficient history (${bars.length} bars), skipping`);
      continue;
    }
    const [cached] = await db.select().from(fundamentalsCacheTable).where(eq(fundamentalsCacheTable.symbol, symbol));
    const fundamentals = cached ? {
      trailingPE: cached.trailingPE,
      forwardPE: cached.forwardPE,
      pegRatio: cached.pegRatio,
      priceToBook: cached.priceToBook,
      revenueGrowth: cached.revenueGrowth,
      earningsGrowth: cached.earningsGrowth,
      grossMargins: cached.grossMargins,
      returnOnEquity: cached.returnOnEquity,
      debtToEquity: cached.debtToEquity
    } : EMPTY_FUNDAMENTALS;
    for (let i = 200; i < bars.length - PREDICTION_HORIZON_DAYS; i++) {
      const features = computeFeaturesAt(bars, i, fundamentals);
      if (!features) continue;
      const entryClose = bars[i].close;
      const futureClose = bars[i + PREDICTION_HORIZON_DAYS].close;
      const forwardReturn = futureClose / entryClose - 1;
      const label = forwardReturn > OUTPERFORM_THRESHOLD ? 1 : 0;
      rows.push({ symbol, date: bars[i].date, features, label });
    }
    log(`[pipeline] ${symbol}: built ${bars.length - 200 - PREDICTION_HORIZON_DAYS} training rows`);
  }
  return rows;
}

// src/lib/ml/train.ts
function chronologicalSplit(rows, testFraction = 0.2) {
  const uniqueDates = Array.from(new Set(rows.map((r) => r.date))).sort();
  const cutoffIdx = Math.floor(uniqueDates.length * (1 - testFraction));
  const cutoffDate = uniqueDates[cutoffIdx];
  const train = rows.filter((r) => r.date < cutoffDate);
  const test = rows.filter((r) => r.date >= cutoffDate);
  return { train, test, cutoffDate };
}
function evaluate(model, X, y) {
  const probs = model.predictProba(X);
  const preds = probs.map((p) => p >= 0.5 ? 1 : 0);
  let correct = 0, truePositive = 0, predictedPositive = 0;
  for (let i = 0; i < y.length; i++) {
    if (preds[i] === y[i]) correct++;
    if (preds[i] === 1) {
      predictedPositive++;
      if (y[i] === 1) truePositive++;
    }
  }
  const accuracy = correct / y.length * 100;
  const winRate = predictedPositive > 0 ? truePositive / predictedPositive * 100 : 0;
  const baseRate = y.reduce((a, b) => a + b, 0) / y.length * 100;
  return { accuracy, winRate, baseRate };
}
async function trainAllModels(log = console.log, onlyKinds2) {
  log(`[train] Fetching history + building training set for ${TRAINING_UNIVERSE.length} symbols\u2026`);
  const rows = await buildTrainingSet(TRAINING_UNIVERSE, log);
  log(`[train] Built ${rows.length} total point-in-time training rows`);
  if (rows.length < 500) {
    throw new Error(`Not enough training data (${rows.length} rows) \u2014 did fetchAndStoreHistory run first?`);
  }
  const { train, test, cutoffDate } = chronologicalSplit(rows);
  log(`[train] Chronological split at ${cutoffDate}: ${train.length} train / ${test.length} test rows`);
  const kinds = onlyKinds2 ?? ["overall", "momentum", "value", "lowRisk"];
  for (const kind of kinds) {
    const group = FEATURE_GROUPS[kind];
    const XTrain = train.map((r) => vectorFor(r.features, group));
    const yTrain = train.map((r) => r.label);
    const XTest = test.map((r) => vectorFor(r.features, group));
    const yTest = test.map((r) => r.label);
    log(`[train] Training "${kind}" model on ${group.length} features\u2026`);
    const model = new GradientBoostedTrees();
    model.fit(XTrain, yTrain);
    const { accuracy, winRate, baseRate } = evaluate(model, XTest, yTest);
    log(`[train] "${kind}" holdout accuracy=${accuracy.toFixed(1)}% winRate=${winRate.toFixed(1)}% baseRate=${baseRate.toFixed(1)}%`);
    const [prevLatest] = await db.select({ version: mlModelsTable.version }).from(mlModelsTable).where(eq(mlModelsTable.kind, kind)).orderBy(desc(mlModelsTable.version)).limit(1);
    const nextVersion = (prevLatest?.version ?? 0) + 1;
    await db.update(mlModelsTable).set({ isActive: false }).where(eq(mlModelsTable.kind, kind));
    await db.insert(mlModelsTable).values({
      kind,
      version: nextVersion,
      horizonDays: PREDICTION_HORIZON_DAYS,
      featureNames: group,
      model: model.toJSON(),
      trainSampleSize: train.length,
      testSampleSize: test.length,
      backtestAccuracy: accuracy,
      backtestWinRate: winRate,
      backtestBaseRate: baseRate,
      isActive: true
    });
    log(`[train] Persisted "${kind}" model v${nextVersion}`);
  }
  log("[train] Done \u2014 all 4 models trained and stored.");
}

// src/scripts/trainOnly.ts
var onlyKinds = process.argv.slice(2);
async function main() {
  await trainAllModels(console.log, onlyKinds.length ? onlyKinds : void 0);
  process.exit(0);
}
main().catch((err) => {
  console.error("[train-only] FAILED:", err);
  process.exit(1);
});
